2	
3	const ITEM_TYPE_PREMIUMS: Record<string, number> = {
4	  Sword: 50,
5	  Amulet: 100,
6	  Staff: 75,
7	  Potion: 60,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE = 1.1;
11	const LOYALTY_DISCOUNT = 0.8; // -20% discount for 2+ years
12	const CURSED_ITEM_SURCHARGE = 1.5;
13	const HIGH_ENCHANTMENT_SURCHARGE = 1.3; // +30% for enchantmentLevel >= 5
14	
15	export interface Item {
16	  type: string;
17	  insuranceModifier?: string;
18	  yearsInsured?: number;
19	  cursed?: boolean;
20	  enchantmentLevel?: number;
21	}
22	
23	const applyModifiers = (premium: number, item: Item): number => {
24	  let adjusted = premium;
25	
26	  // Apply first insurance surcharge
27	  if (item.insuranceModifier === "first") {
28	    adjusted *= FIRST_INSURANCE_SURCHARGE;
29	  }
30	
31	  // Apply loyalty discount
32	  if (item.yearsInsured !== undefined && item.yearsInsured >= 2) {
33	    adjusted *= LOYALTY_DISCOUNT;
34	  }
35	
36	  // Apply cursed surcharge
37	  if (item.cursed === true) {
38	    adjusted *= CURSED_ITEM_SURCHARGE;
39	  }
40	
41	  // Apply enchantment surcharge
42	  if (item.enchantmentLevel !== undefined && item.enchantmentLevel >= 5) {
43	    adjusted *= HIGH_ENCHANTMENT_SURCHARGE;
44	  }
45	
46	  return adjusted;
47	};
48	
49	const roundUpInMHPCOsFavor = (value: number): number => {
50	  const standardRound = Math.round(value);
51	  return value > standardRound ? standardRound + 1 : standardRound;
52	};
53	
54	export function quotePolicy(items: Item[]): number {
55	  const total = items.reduce((sum, item) => {
56	    if (!(item.type in ITEM_TYPE_PREMIUMS)) {
57	      throw new Error(`Unknown item type: ${item.type}`);
58	    }
59	    const basePremium = ITEM_TYPE_PREMIUMS[item.type];
60	    const adjustedPremium = applyModifiers(basePremium, item);
61	    return sum + Math.round(adjustedPremium * 100) / 100;
62	  }, 0);
63	  return roundUpInMHPCOsFavor(total);
64	}
65	
66	const INDIVIDUAL_COMPONENT_PRICE = 25;
67	const COMPONENT_BLOCK_SIZE = 3;
68	const COMPONENT_BLOCK_PRICE = 60;
69	
70	const CLAIM_DEDUCTIBLE = 100;
71	const INSURANCE_CAP_MULTIPLIER = 2;
72	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
73	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
74	
75	export function quoteComponent(items: Item[]): number {
76	  const isComponentBlock = items.length === COMPONENT_BLOCK_SIZE;
77	  return isComponentBlock ? COMPONENT_BLOCK_PRICE : INDIVIDUAL_COMPONENT_PRICE;
78	}
79	
80	const applyInsuranceCap = (amount: number, insuranceSum: number, dragonMaterial: boolean): number => {
81	  if (dragonMaterial) {
82	    return amount;
83	  }
84	  const cap = insuranceSum * INSURANCE_CAP_MULTIPLIER;
85	  return Math.min(amount, cap);
86	};
87	
88	const applyEnchantmentReduction = (reimbursement: number, enchantmentLevel?: number): number => {
89	  if (enchantmentLevel !== undefined && enchantmentLevel >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD) {
90	    return reimbursement * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
91	  }
92	  return reimbursement;
93	};
94	
95	export function processClaim(damage: number, insuranceSum?: number, enchantmentLevel?: number, dragonMaterial?: boolean): number {
96	  const afterDeductible = damage - CLAIM_DEDUCTIBLE;
97	  if (insuranceSum !== undefined) {
98	    const cappedAmount = applyInsuranceCap(afterDeductible, insuranceSum, dragonMaterial ?? false);
99	    return applyEnchantmentReduction(cappedAmount, enchantmentLevel);
100	  }
101	  return afterDeductible;
102	}
